export const ARSENAL_MOCK_HTML = "<!doctype html>\n<html lang=\"pt-br\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n<title>Arsenal Inteligente \u00b7 Mockups de E-mails</title>\n<style>\n:root{\n  --bg:#000000;\n  --panel:#000000;\n  --line:#1D1D1F;\n  --line-soft:#111113;\n  --text:#F5F5F7;\n  --muted:#A1A1AA;\n  --dim:#66666E;\n  --white:#FFFFFF;\n  --green:#28C840;\n  --yellow:#FFBD2E;\n  --red:#B00020;\n}\n*{box-sizing:border-box}\nbody{margin:0;background:#000000;color:var(--text);font-family:-apple-system,BlinkMacSystemFont,\"SF Pro Display\",\"SF Pro Text\",\"Helvetica Neue\",Arial,sans-serif;}\n.page{max-width:980px;margin:0 auto;padding:34px 18px 72px;background:#000000;}\n.kicker{font-size:11px;letter-spacing:.22em;text-transform:uppercase;color:var(--dim);margin:0 0 10px;font-weight:700;}\nh1{font-size:34px;letter-spacing:-.035em;line-height:1.05;margin:0 0 12px;font-weight:760;color:#fff;}\n.lead{max-width:760px;color:var(--muted);font-size:15px;line-height:1.7;margin:0 0 26px;}\n.guardrail{border:1px solid var(--line);border-radius:18px;padding:18px 20px;margin:0 0 28px;background:#000;}\n.guardrail h3{font-size:13px;text-transform:uppercase;letter-spacing:.14em;color:#fff;margin:0 0 12px;}\n.guardrail p{font-size:13px;line-height:1.65;color:var(--muted);margin:0 0 10px;}\n.token-list{display:flex;gap:8px;flex-wrap:wrap;margin-top:14px;}\n.token{font-size:12px;color:#E8E8ED;background:#09090A;border:1px solid var(--line);border-radius:999px;padding:7px 10px;font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,\"Liberation Mono\",monospace;}\n.section-title{margin:38px 0 12px;font-size:12px;text-transform:uppercase;letter-spacing:.18em;color:#fff;font-weight:800;}\n.mock-label{display:flex;align-items:center;justify-content:space-between;gap:14px;margin:0 auto 8px;max-width:640px;color:var(--dim);font-size:11px;letter-spacing:.16em;text-transform:uppercase;font-weight:800;}\n.status-dot{width:9px;height:9px;border-radius:50%;display:inline-block;margin-right:8px;vertical-align:middle;background:var(--status)}\n.email{width:100%;max-width:640px;margin:0 auto 34px;background:#000;border:1px solid var(--line);border-radius:18px;overflow:hidden;box-shadow:0 0 0 1px rgba(255,255,255,.015),0 20px 60px rgba(0,0,0,.55);}\n.email-top{height:4px;background:var(--status)}\n.email-header{padding:24px 34px 18px;border-bottom:1px solid var(--line-soft);display:flex;align-items:center;justify-content:space-between;gap:18px;}\n.brand{display:flex;align-items:center;gap:14px;min-width:0;}\n.brand-logo{display:block;width:132px;max-width:132px;height:auto;border:0;outline:none;flex:0 0 auto;}\n.brand-mark{width:32px;height:32px;border:1px solid var(--status);border-radius:9px;display:flex;align-items:center;justify-content:center;color:var(--status);font-weight:900;font-size:12px;letter-spacing:-.04em;}\n.brand-name{line-height:1.08;min-width:0}.brand-name strong{display:block;font-size:14px;color:#fff;letter-spacing:.02em}.brand-name span{display:block;font-size:11px;color:var(--muted);margin-top:3px;}\n.header-code{font-size:10px;color:var(--dim);letter-spacing:.18em;text-transform:uppercase;text-align:right;font-weight:800;}\n.email-body{padding:28px 34px 34px;}\n.state{font-size:12px;color:var(--status);text-transform:uppercase;letter-spacing:.16em;font-weight:900;margin:0 0 16px;}\nh2{font-size:24px;line-height:1.18;letter-spacing:-.03em;font-weight:760;color:#fff;margin:0 0 13px;}\n.copy{font-size:14.5px;line-height:1.72;color:#B8B8C0;margin:0 0 24px;}\n.meta{width:100%;border-collapse:collapse;margin:0 0 26px;font-size:13px;}\n.meta td{padding:10px 0;border-bottom:1px solid var(--line-soft);vertical-align:top;}\n.meta tr:last-child td{border-bottom:0}.meta td:first-child{color:#74747E;text-transform:uppercase;letter-spacing:.10em;font-size:11px;font-weight:800;padding-right:18px;white-space:nowrap;}.meta td:last-child{color:#F2F2F4;text-align:right;font-weight:650;}\n.cta{display:inline-block;background:var(--status);color:var(--status-fg);text-decoration:none;padding:13px 22px;border-radius:9px;font-size:12px;font-weight:900;letter-spacing:.08em;text-transform:uppercase;}\n.email-footer{border-top:1px solid var(--line-soft);padding:18px 34px 24px;color:#5F5F68;font-size:11px;line-height:1.6;}\n.email-footer a{color:var(--status);text-decoration:none;font-weight:800;}\n.note{max-width:640px;margin:-18px auto 38px;color:#5F5F68;font-size:12px;line-height:1.65;}\n@media (max-width:680px){.brand-logo{width:118px;max-width:118px}.page{padding:24px 12px 50px}.email-header,.email-body,.email-footer{padding-left:22px;padding-right:22px}.mock-label{padding:0 4px}.header-code{display:none}.meta td:first-child{white-space:normal}.meta td:last-child{text-align:left}.meta td{display:block;border-bottom:0;padding:7px 0}.meta tr{display:block;border-bottom:1px solid var(--line-soft);padding:6px 0}.meta tr:last-child{border-bottom:0}}\n</style>\n</head>\n<body>\n  <main class=\"page\">\n    <p class=\"kicker\">// MOCKUPS \u00b7 E-MAILS TRANSACIONAIS</p>\n    <h1>Arsenal Inteligente \u00b7 Mockups de E-mails</h1>\n    <p class=\"lead\">Fluxos exclusivos para clientes que contrataram apenas monitoramento, controle de documentos, validade e alertas do acervo. N\u00e3o h\u00e1 promessa de protocolo, recurso, regulariza\u00e7\u00e3o ou condu\u00e7\u00e3o administrativa sem contrata\u00e7\u00e3o de servi\u00e7o.</p>\n    <section class=\"guardrail\">\n      <h3>Escopo deste arquivo</h3>\n      <p>Usar somente para o produto Arsenal Inteligente. O cliente cadastra documentos e a Quero Armas monitora prazos, valida arquivos e emite alertas. Quando a a\u00e7\u00e3o virar renova\u00e7\u00e3o, protocolo ou regulariza\u00e7\u00e3o, o texto direciona para contrata\u00e7\u00e3o do servi\u00e7o correspondente.</p>\n      <div class=\"token-list\"><span class=\"token\">{{nome_cliente}}</span><span class=\"token\">{{nome_documento}}</span><span class=\"token\">{{tipo_documento}}</span><span class=\"token\">{{data_vencimento}}</span><span class=\"token\">{{dias_restantes}}</span><span class=\"token\">{{fabricante_armamento}}</span><span class=\"token\">{{modelo_armamento}}</span><span class=\"token\">{{numero_serie}}</span><span class=\"token\">{{sistema_origem}}</span><span class=\"token\">{{link_hub}}</span></div>\n    </section>\n    <p class=\"section-title\">Mockups separados</p>\n    \n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#FFFFFF\"></span>01 \u00b7 Boas-vindas ao Arsenal Inteligente</span><span>Branco</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#FFFFFF;--status-fg:#000000\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Acesso ativado</div>\n    <h2>Seu Arsenal Inteligente est\u00e1 ativo</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. Seu painel de controle foi ativado. A partir de agora, os documentos cadastrados no Arsenal Inteligente ficar\u00e3o organizados por validade, tipo, sistema de origem e, quando houver v\u00ednculo, pelo armamento {{fabricante_armamento}} {{modelo_armamento}}. Voc\u00ea envia o documento; n\u00f3s registramos, monitoramos e avisamos quando algo realmente depender de voc\u00ea.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Plano</td><td>Controle de prazos e documentos</td></tr>\n<tr><td>Escopo</td><td>Monitoramento do acervo</td></tr>\n<tr><td>A\u00e7\u00e3o inicial</td><td>Cadastrar documentos</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Acessar Arsenal Inteligente \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#28C840\"></span>02 \u00b7 Documento cadastrado no acervo</span><span>Verde grama</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#28C840;--status-fg:#021006\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Documento cadastrado</div>\n    <h2>{{nome_documento}} entrou no seu radar</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. {{nome_documento}} foi cadastrado no Arsenal Inteligente e passou a compor seu acervo monitorado. Quando aplic\u00e1vel, o documento ficar\u00e1 vinculado ao armamento {{fabricante_armamento}} {{modelo_armamento}}, n\u00ba de s\u00e9rie {{numero_serie}}, e ao sistema {{sistema_origem}}.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Tipo</td><td>{{tipo_documento}}</td></tr>\n<tr><td>Sistema</td><td>{{sistema_origem}}</td></tr>\n<tr><td>Status</td><td>Cadastrado e monitorado</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Ver documento no Arsenal \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#FFBD2E\"></span>03 \u00b7 Documento recebido para confer\u00eancia</span><span>Amarelo macOS</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#FFBD2E;--status-fg:#171100\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Recebido para confer\u00eancia</div>\n    <h2>Recebemos {{nome_documento}}</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. {{nome_documento}} foi recebido no Arsenal Inteligente. Faremos a confer\u00eancia de legibilidade, validade e dados principais antes de posicionar o documento no radar. Se houver algo que dependa de voc\u00ea, enviaremos uma orienta\u00e7\u00e3o objetiva pelo Hub.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Recebido em</td><td>{{data_recebimento}}</td></tr>\n<tr><td>Status</td><td>Confer\u00eancia ser\u00e1 iniciada</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Acompanhar confer\u00eancia \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#28C840\"></span>04 \u00b7 Documento validado e monitorado</span><span>Verde grama</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#28C840;--status-fg:#021006\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Validado</div>\n    <h2>{{nome_documento}} foi validado</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. {{nome_documento}} foi conferido, validado e registrado no radar do Arsenal Inteligente. A partir daqui, voc\u00ea n\u00e3o precisa controlar este prazo manualmente: avisaremos com anteced\u00eancia quando houver janela preventiva, vencimento ou atualiza\u00e7\u00e3o necess\u00e1ria.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Validade</td><td>{{data_vencimento}}</td></tr>\n<tr><td>Status</td><td>Validado e monitorado</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Ver no Arsenal \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#FFBD2E\"></span>05 \u00b7 Pend\u00eancia no arquivo enviado</span><span>Amarelo macOS</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#FFBD2E;--status-fg:#171100\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">A\u00e7\u00e3o necess\u00e1ria</div>\n    <h2>Precisamos corrigir {{nome_documento}}</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. Durante a confer\u00eancia de {{nome_documento}}, identificamos uma pend\u00eancia no arquivo enviado: {{motivo_pendencia}}. O controle do prazo continua no Arsenal Inteligente, mas precisamos que voc\u00ea reenvie o documento corrigido para concluir o cadastro.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Pend\u00eancia</td><td>{{motivo_pendencia}}</td></tr>\n<tr><td>Status</td><td>Aguardando reenvio</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Reenviar documento \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#FFBD2E\"></span>06 \u00b7 Documento pr\u00f3ximo do vencimento</span><span>Amarelo macOS</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#FFBD2E;--status-fg:#171100\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Janela preventiva</div>\n    <h2>{{nome_documento}} vence em {{dias_restantes}} dias</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. {{nome_documento}} entrou na janela preventiva de vencimento. O Arsenal Inteligente colocou este prazo em destaque para que voc\u00ea n\u00e3o seja surpreendido. Caso deseje que a Quero Armas assuma a renova\u00e7\u00e3o ou regulariza\u00e7\u00e3o, solicite o servi\u00e7o pelo Hub.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Vencimento</td><td>{{data_vencimento}}</td></tr>\n<tr><td>Restam</td><td>{{dias_restantes}} dias</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Ver prazo no Arsenal \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#B00020\"></span>07 \u00b7 Documento vencido</span><span>Vermelho sangue</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#B00020;--status-fg:#FFFFFF\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Vencido</div>\n    <h2>{{nome_documento}} consta como vencido</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. {{nome_documento}} consta como vencido no Arsenal Inteligente desde {{data_vencimento}}. Este aviso \u00e9 de monitoramento: para renovar, regularizar ou abrir um procedimento, ser\u00e1 necess\u00e1rio solicitar o servi\u00e7o correspondente \u00e0 Quero Armas pelo Hub.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Venceu em</td><td>{{data_vencimento}}</td></tr>\n<tr><td>Status</td><td>Vencido</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Ver documento vencido \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#28C840\"></span>08 \u00b7 Acervo sem pend\u00eancias imediatas</span><span>Verde grama</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#28C840;--status-fg:#021006\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Radar regular</div>\n    <h2>Seu acervo est\u00e1 sem alertas cr\u00edticos</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. No momento, os documentos cadastrados no Arsenal Inteligente n\u00e3o apresentam vencimento cr\u00edtico ou pend\u00eancia imediata. Continuaremos monitorando o acervo e avisaremos quando surgir qualquer a\u00e7\u00e3o que dependa de voc\u00ea.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Per\u00edodo analisado</td><td>{{periodo_resumo}}</td></tr>\n<tr><td>Status</td><td>Sem pend\u00eancias cr\u00edticas</td></tr>\n<tr><td>Pr\u00f3ximo alerta</td><td>Autom\u00e1tico</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Acessar painel \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#28C840\"></span>09 \u00b7 Novo prazo registrado</span><span>Verde grama</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#28C840;--status-fg:#021006\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Prazo registrado</div>\n    <h2>Novo vencimento de {{nome_documento}} cadastrado</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. Registramos a nova validade de {{nome_documento}} no Arsenal Inteligente. O documento ficar\u00e1 monitorado at\u00e9 {{data_vencimento}}, com alertas preventivos antes da data cr\u00edtica.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Nova validade</td><td>{{data_vencimento}}</td></tr>\n<tr><td>Status</td><td>Prazo monitorado</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Ver prazo cadastrado \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#FFBD2E\"></span>10 \u00b7 Atualiza\u00e7\u00e3o de dados do acervo</span><span>Amarelo macOS</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#FFBD2E;--status-fg:#171100\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Atualiza\u00e7\u00e3o recomendada</div>\n    <h2>Atualize os dados de {{nome_documento}}</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. Detectamos que {{nome_documento}} pode precisar de atualiza\u00e7\u00e3o cadastral no Arsenal Inteligente. Confirme os dados do documento, do sistema {{sistema_origem}} e, quando aplic\u00e1vel, do armamento {{fabricante_armamento}} {{modelo_armamento}} para manter o monitoramento preciso.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Sistema</td><td>{{sistema_origem}}</td></tr>\n<tr><td>Status</td><td>Aguardando confirma\u00e7\u00e3o</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Atualizar dados \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#FFFFFF\"></span>11 \u00b7 Resumo peri\u00f3dico do acervo</span><span>Branco</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#FFFFFF;--status-fg:#000000\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Resumo do radar</div>\n    <h2>Resumo do seu acervo monitorado</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. Este \u00e9 o resumo do per\u00edodo {{periodo_resumo}}. O Arsenal Inteligente consolidou seus documentos, prazos ativos, vencimentos futuros e pend\u00eancias de arquivo em um \u00fanico painel para facilitar sua tomada de decis\u00e3o.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Per\u00edodo</td><td>{{periodo_resumo}}</td></tr>\n<tr><td>Documentos monitorados</td><td>{{total_documentos}}</td></tr>\n<tr><td>Alertas ativos</td><td>{{total_alertas}}</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Ver resumo completo \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n\n<div class=\"mock-label\"><span><span class=\"status-dot\" style=\"--status:#FFBD2E\"></span>12 \u00b7 Arquivo ileg\u00edvel ou incompat\u00edvel</span><span>Amarelo macOS</span></div>\n<table class=\"email\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"--status:#FFBD2E;--status-fg:#171100\">\n  <tr><td class=\"email-top\"></td></tr>\n  <tr><td class=\"email-header\">\n    <div class=\"brand\"><img class=\"brand-logo\" src=\"data:image/png;base64,\" width=\"132\" alt=\"Quero Armas\" style=\"display:block;border:0;outline:none;filter:brightness(0) invert(1);\"></div>\n    <div class=\"header-code\">// ARSENAL INTELIGENTE</div>\n  </td></tr>\n  <tr><td class=\"email-body\">\n    <div class=\"state\">Leitura n\u00e3o conclu\u00edda</div>\n    <h2>N\u00e3o foi poss\u00edvel validar {{nome_documento}}</h2>\n    <p class=\"copy\">Ol\u00e1, {{nome_cliente}}. O arquivo enviado para {{nome_documento}} n\u00e3o p\u00f4de ser validado porque est\u00e1 ileg\u00edvel, incompleto ou em formato incompat\u00edvel. Reenvie uma vers\u00e3o n\u00edtida para que o Arsenal Inteligente consiga registrar os dados e iniciar o monitoramento corretamente.</p>\n    <table class=\"meta\" role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\"><tr><td>Documento</td><td>{{nome_documento}}</td></tr>\n<tr><td>Motivo</td><td>{{motivo_pendencia}}</td></tr>\n<tr><td>Status</td><td>Aguardando novo arquivo</td></tr></table>\n    <a class=\"cta\" href=\"{{link_hub}}\">Enviar novo arquivo \u2192</a>\n  </td></tr>\n  <tr><td class=\"email-footer\">\n    Quero Armas \u00b7 Hub de Documentos<br>\n    Voc\u00ea recebe este aviso porque existe uma atualiza\u00e7\u00e3o vinculada ao seu painel. <a href=\"{{link_gerenciar_avisos}}\">Gerenciar avisos</a>\n  </td></tr>\n</table>\n\n  </main>\n</body>\n</html>\n";
